import{_ as a,o as i,c as l,a4 as n}from"./chunks/framework.DkKDtR5x.js";const g=JSON.parse('{"title":"AI for Java Developers","description":"","frontmatter":{},"headers":[],"relativePath":"ai/introduction.md","filePath":"ai/introduction.md"}'),t={name:"ai/introduction.md"};function r(o,e,s,d,c,p){return i(),l("div",null,[...e[0]||(e[0]=[n('<h1 id="ai-for-java-developers" tabindex="-1">AI for Java Developers <a class="header-anchor" href="#ai-for-java-developers" aria-label="Permalink to “AI for Java Developers”">​</a></h1><ul><li>Enhance Problem Solving Abilities</li></ul><h2 id="glossary-of-terms" tabindex="-1">Glossary of Terms <a class="header-anchor" href="#glossary-of-terms" aria-label="Permalink to “Glossary of Terms”">​</a></h2><ul><li>LLM - Large Language Models</li><li>NLP - Natural Language Processing : Enabling machines to understand, interpret and generate Human (Natural) Language.</li><li>OpenAI -</li><li>GPT - Generative Pretrained Transformer</li><li>ChatGPT - AI-powered conversational chatbot using OpenAI GPT models as LLM</li><li>RAG -</li></ul><h2 id="llms-and-their-evolution" tabindex="-1">LLMs and their Evolution <a class="header-anchor" href="#llms-and-their-evolution" aria-label="Permalink to “LLMs and their Evolution”">​</a></h2><ul><li>Large Language Model is a type of AI designed to understand, generate, and summarize human-like text by analyzing massive datasets using deep learning, specifically transformer architectures.</li><li>LLMs work by predicting the next word in a sequence based on prompt context, enabling tasks like chatbot interaction, translation, and code generation.</li><li>Populat LLMs <ul><li>GPT models by OpenAI</li><li>Gemini by Google</li><li>Claude by Anthropic</li><li>Llama by Meta</li></ul></li><li>ChatGPT uses gpt-models of OpenAI behind the scenes</li></ul><h3 id="building-bloacks-of-llm-and-nlp" tabindex="-1">Building Bloacks of LLM and NLP <a class="header-anchor" href="#building-bloacks-of-llm-and-nlp" aria-label="Permalink to “Building Bloacks of LLM and NLP”">​</a></h3><ul><li>Artificial Intelligence : computer systems designed to carry out tasks that normally need human intelligence</li><li>Machine Learning : Focuses on building algorithms that allow the system to learn by itself.</li><li>Deep Learning : Branch of ML focusing on algorithms that lead to Artificial Neural Networks. These excel inprocessing vast amount of data and are highly effective in tasks like image and speech recognition, as well as NLP</li><li>GPT (Generative Pretrained Transformer) : Based on Transformer Architecture, Uses attention mechanism to understand</li></ul><p><img src="https://www.researchgate.net/publication/373797588/figure/fig1/AS:11431281390168704@1745252497113/A-comparative-view-of-AI-machine-learning-deep-learning-and-generative-AI-source.tif" alt="Image"></p><h3 id="evolution" tabindex="-1">Evolution <a class="header-anchor" href="#evolution" aria-label="Permalink to “Evolution”">​</a></h3><ul><li>n-grams</li><li>Neural Language Models (RNNs and LSTM)</li><li>Transformer Architecture</li><li>LLMs (GPTs)</li></ul><h3 id="popular-llm-models" tabindex="-1">Popular LLM Models <a class="header-anchor" href="#popular-llm-models" aria-label="Permalink to “Popular LLM Models”">​</a></h3><ul><li>Properiatary/Closed Source Models : <ul><li>Not available for public download or modification</li><li>Paid services accessed through API calls</li><li>Examples <ul><li>OpenAI - GPT</li><li>Gemini by Google</li><li>Claude by Anthropic</li></ul></li></ul></li><li>Open Source Models : <ul><li>Free available for Public</li><li>Examples <ul><li>LLaMA by Meta</li><li>Mistral by MistralAI</li></ul></li></ul></li></ul><p><img src="https://www.youngurbanproject.com/wp-content/uploads/2025/01/How-Are-LLMs-Trained.jpg" alt="How-Are-LLMs-Trained.jpg" width="400px">|<a href="https://microsoft.github.io/Workshop-Interact-with-OpenAI-models/llms/" target="_blank"><img src="https://microsoft.github.io/Workshop-Interact-with-OpenAI-models/assets/images/llm-001-da6e9df83e520a18f43984ad5118b9a7.png" alt="How large is an LLM?" width="600px"></a></p><h3 id="advantages" tabindex="-1">Advantages <a class="header-anchor" href="#advantages" aria-label="Permalink to “Advantages”">​</a></h3><ul><li>Multilingual Capabilities</li><li>Creativity and Content Generation</li><li>Automation of Complex Task</li><li>Rapid Prototyping</li></ul><h3 id="challenges" tabindex="-1">Challenges <a class="header-anchor" href="#challenges" aria-label="Permalink to “Challenges”">​</a></h3><ul><li>Bias and Fairness</li><li>Ethical Concerns - Fake news, Deepfakes</li><li>Lack of Explainability - Industries like Legal, Medical or Financial</li><li>Depends in Data Quality - Outdated data, biased data</li><li>Knowledge CutOff</li><li>Hallucination</li></ul><blockquote><p>!NOTE</p><p>Developers can now use the power of NLP to build many different kinds of applications</p></blockquote><h3 id="ai-applications-using-llm" tabindex="-1">AI applications using LLM <a class="header-anchor" href="#ai-applications-using-llm" aria-label="Permalink to “AI applications using LLM”">​</a></h3><ul><li>Customer support and Chatbots</li><li>Document Automation</li><li>HR and Recruitment</li><li>Healthcare</li><li>Finance</li><li>IT and DevOps</li><li>Travel education and Training</li></ul><h2 id="prompt-engineering-for-genrative-ai" tabindex="-1">Prompt Engineering for Genrative AI <a class="header-anchor" href="#prompt-engineering-for-genrative-ai" aria-label="Permalink to “Prompt Engineering for Genrative AI”">​</a></h2><p><img src="https://promptengineering.org/content/images/size/w1000/2023/08/Prompt-engineering---Large-Language-Model-LLM--Basic-LLM-Prompt-Cycle--PromptEngineering.org.jpg" alt="LLM Prompt Cycle - PromptEngineering" width="500px"></p><h2 id="llm-safety-guide" tabindex="-1">LLM Safety Guide <a class="header-anchor" href="#llm-safety-guide" aria-label="Permalink to “LLM Safety Guide”">​</a></h2><p><a href="https://www.confident-ai.com/blog/the-comprehensive-llm-safety-guide-navigate-ai-regulations-and-best-practices-for-llm-safety" target="_blank" rel="noreferrer"><img src="https://images.ctfassets.net/otwaplf7zuwf/4RNUq2ojMRbubXXWyfilMF/55a7551842db56a774750c9201ed364a/image.png" alt="" width="500px"></a>|<img src="https://images.ctfassets.net/otwaplf7zuwf/3EJUSvZYzUly4cYy2huH1p/74eafd8eaaa48999d772be60c7c314d8/image.png" alt="" width="500px"></p>',25)])])}const h=a(t,[["render",r]]);export{g as __pageData,h as default};
